-- 3) Minimal SQL parsing from raw JSON into flat tables
SELECT raw_id, run_id, benchmark, measure, value, lower_value, upper_value, unit
FROM v_scalar_raw_extract
ORDER BY raw_id, benchmark, measure;

SELECT raw_id, run_id, benchmark, measure, series, point_idx, value, lower_value, upper_value, unit
FROM v_vector_raw_extract
ORDER BY raw_id, benchmark, measure, series, point_idx;

