-- 5) Keep sequences aligned with inserted explicit IDs
SELECT setval(pg_get_serial_sequence('test_run', 'run_id'), (SELECT COALESCE(MAX(run_id), 1) FROM test_run), true);
SELECT setval(pg_get_serial_sequence('raw_result', 'raw_id'), (SELECT COALESCE(MAX(raw_id), 1) FROM raw_result), true);
SELECT setval(pg_get_serial_sequence('run_event', 'event_id'), (SELECT COALESCE(MAX(event_id), 1) FROM run_event), true);

